export function parseArgs(argv) {
  const result = { _: [] }
  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      continue
    }
    if (arg.includes('=')) {
      const key = arg.slice(2)
      const value = arg.slice(key.length + 1)
      result[key] = value
      continue
    }
    if (i + 1 < argv.length && argv[i + 1] && argv[i + 1].startsWith('--') === false) {
      result[arg.slice(2)] = argv[i + 1]
      i += 1
      continue
    }
    result[arg.slice(2)] = true
  }
  return result
}

